@namespace Lumeo

<nav role="navigation" aria-label="pagination" class="@CssClass" @attributes="AdditionalAttributes">
    @ChildContent
</nav>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("mx-auto flex w-full justify-center", Class);
}

@namespace Lumeo

<ul class="@CssClass" @attributes="AdditionalAttributes">
    @ChildContent
</ul>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("flex flex-row items-center gap-1", Class);
}

@namespace Lumeo
@inject Lumeo.Services.Localization.ILumeoLocalizer L

<li>
    <span class="@CssClass" @attributes="AdditionalAttributes">
        <Blazicon Svg="Lucide.Ellipsis" class="h-4 w-4" />
        <span class="sr-only">@L["Pagination.MorePages"]</span>
    </span>
</li>

@code {
    [CascadingParameter] private Lumeo.Density? Density { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Tracks the ambient DensityScope so the ellipsis aligns with the page
    // cells; Comfortable reproduces the historical `h-9 w-9`.
    private string SizeClass => Density switch
    {
        Lumeo.Density.Compact => "h-8 w-8",
        Lumeo.Density.Spacious => "h-10 w-10",
        _ => "h-9 w-9"
    };

    private string CssClass => Cx.Merge("flex", SizeClass, "items-center justify-center", Class);
}

@namespace Lumeo

<li>
    <button type="button" class="@CssClass" aria-current="@(IsActive ? "page" : null)" @onclick="OnClick" @attributes="AdditionalAttributes">
        @ChildContent
    </button>
</li>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback OnClick { get; set; }
    [CascadingParameter] private Lumeo.Density? Density { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Desktop cell size tracks the ambient DensityScope; the mobile touch
    // floor (h-11 w-11) is kept so pages stay tappable. Comfortable
    // reproduces the historical `sm:h-9 sm:w-9`.
    private string SizeClass => Density switch
    {
        Lumeo.Density.Compact => "h-11 w-11 sm:h-8 sm:w-8",
        Lumeo.Density.Spacious => "h-11 w-11 sm:h-10 sm:w-10",
        _ => "h-11 w-11 sm:h-9 sm:w-9"
    };

    private string CssClass => Cx.Merge("inline-flex items-center justify-center whitespace-nowrap rounded-md text-sm font-medium cursor-pointer transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2", SizeClass, (IsActive ? "border border-input bg-background shadow-sm" : "hover:bg-accent hover:text-accent-foreground"), Class);
}

@namespace Lumeo
@inject Lumeo.Services.Localization.ILumeoLocalizer L

<li>
    <button type="button" class="@CssClass" @onclick="OnClick" disabled="@Disabled" aria-label="@L["Pagination.Next"]" @attributes="AdditionalAttributes">
        <span>@L["Pagination.Next"]</span>
        <Blazicon Svg="Lucide.ChevronRight" class="h-4 w-4 [dir=rtl]:rotate-180" />
    </button>
</li>

@code {
    [Parameter] public EventCallback OnClick { get; set; }
    [Parameter] public bool Disabled { get; set; }
    [CascadingParameter] private Lumeo.Density? Density { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Desktop height + horizontal padding track the ambient DensityScope; the
    // mobile touch floor (h-11) is kept. Comfortable reproduces `sm:h-9 px-3`.
    private string SizeClass => Density switch
    {
        Lumeo.Density.Compact => "h-11 sm:h-8 px-2.5",
        Lumeo.Density.Spacious => "h-11 sm:h-10 px-4",
        _ => "h-11 sm:h-9 px-3"
    };

    private string CssClass => Cx.Merge("inline-flex items-center justify-center gap-1 whitespace-nowrap rounded-md text-sm font-medium transition-colors hover:bg-accent hover:text-accent-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-2", SizeClass, "disabled:pointer-events-none disabled:opacity-50", Class);
}

@namespace Lumeo
@inject Lumeo.Services.Localization.ILumeoLocalizer L

<li>
